mapper.update:
		update cotdl.tbl_piiconfkeymap
		set 
			key_cols= #{key_cols, jdbcType=VARCHAR},
			src_owner= #{src_owner, jdbcType=VARCHAR},
			src_table_name= #{src_table_name, jdbcType=VARCHAR},
			where_col= #{where_col, jdbcType=VARCHAR},
			where_key_name= #{where_key_name, jdbcType=VARCHAR},
			parallelcnt= #{parallelcnt, jdbcType=VARCHAR},
			status= #{status, jdbcType=VARCHAR},
			sqltype= #{sqltype, jdbcType=VARCHAR},
			insertstr= #{insertstr, jdbcType=VARCHAR},
			wherestr= #{wherestr, jdbcType=VARCHAR},
			refstr= #{refstr, jdbcType=VARCHAR},
			regdate= str_to_date(#{regdate, jdbcType=VARCHAR},'%Y/%m/%d'),
			upddate= NOW(),
			reguserid= #{reguserid, jdbcType=VARCHAR},
			upduserid= #{upduserid, jdbcType=VARCHAR}
		where keymap_id= #{keymap_id, jdbcType=VARCHAR}
			and key_name= #{key_name, jdbcType=VARCHAR}
			and	db= #{db, jdbcType=VARCHAR}
			and	seq1= #{seq1}
			and	seq2= #{seq2}
			and	seq3= #{seq3}
